:root {
  --bg: #f1f5f9;
  --surface: #ffffffd9;
  --surfaceSolid: #fff;
  --text: #0f172a;
  --muted: #64748b;
  --border: #0f172a14;
  --shadow: 0 10px 30px #0f172a14;
  --bg-grad: radial-gradient(1200px 600px at 20% -10%, #e0e7ff 0%, transparent 55%), radial-gradient(1200px 600px at 90% 0%, #d1fae5 0%, transparent 55%), #f1f5f9;
}

html[data-theme="dark"] {
  --bg: #020617;
  --surface: #0f172abf;
  --surfaceSolid: #0f172a;
  --text: #f1f5f9;
  --muted: #94a3b8;
  --border: #94a3b82e;
  --shadow: 0 10px 30px #00000073;
  --bg-grad: radial-gradient(1200px 600px at 20% -10%, #6366f126 0%, transparent 55%), radial-gradient(1200px 600px at 90% 0%, #10b98126 0%, transparent 55%), #020617;
}

html, body {
  background: var(--bg);
  width: 100%;
  height: auto;
  min-height: 100vh;
  color: var(--text);
  -webkit-font-smoothing: antialiased;
  -webkit-overflow-scrolling: touch;
  margin: 0;
  padding: 0;
  font-family: system-ui, -apple-system, sans-serif;
  display: block;
  overflow-x: hidden;
  overflow-y: auto !important;
}

input, select, textarea {
  outline: none;
  width: 100%;
  transition: all .2s ease-in-out;
  box-shadow: 0 1px 2px #0000000d;
  background-color: var(--surfaceSolid) !important;
  border: 1px solid var(--border-color) !important;
  color: var(--text) !important;
  border-radius: 12px !important;
  padding: 12px 16px !important;
  font-size: 16px !important;
  font-weight: 600 !important;
}

input:focus, select:focus, textarea:focus {
  border-color: var(--accent-blue) !important;
  box-shadow: 0 0 0 3px #3b82f626 !important;
}

label {
  text-transform: uppercase;
  letter-spacing: .5px;
  margin-bottom: 6px;
  display: block;
  color: var(--muted) !important;
  font-size: 11px !important;
  font-weight: 700 !important;
}

button {
  cursor: pointer;
  font-weight: 700;
  transition: transform .1s, background-color .2s;
}

button:active {
  transform: scale(.98);
}

main {
  min-height: 100vh;
  padding-bottom: calc(100px + env(safe-area-inset-bottom));
  display: block;
}

::-webkit-scrollbar {
  width: 8px;
}

::-webkit-scrollbar-track {
  background: var(--bg);
}

::-webkit-scrollbar-thumb {
  background: var(--muted);
  border-radius: 10px;
}

html[data-theme="dark"] ::-webkit-scrollbar-thumb {
  background: var(--muted);
}

::-webkit-scrollbar-thumb:hover {
  background: var(--muted);
}

html[data-theme="dark"] ::-webkit-scrollbar-thumb:hover {
  background: var(--muted);
}

